+fn string_set(values: &[Value], key: &str) -> std::collections::BTreeSet<String> {
+    values
+        .iter()
+        .map(|value| {
+            value
+                .get(key)
+                .and_then(Value::as_str)
+                .unwrap_or_else(|| panic!("missing `{key}` in manifest entry: {value}"))
+                .to_string()
+        })
+        .collect()
+}
